import React, {
    createContext,
    type FC,
    type PropsWithChildren,
    useCallback,
    useContext,
} from 'react';
import type {Permissions} from "@lmb-it/kitsconcerto-types";

type IPermissionsContextValues = {
    check:(permissions: string | string[] | Permissions | null)=>boolean;
}
const PermissionsContext = createContext<IPermissionsContextValues>({} as IPermissionsContextValues);

const PermissionsProvider: FC<PropsWithChildren<{ roles?:string[] | null }>> = ({children, roles}) => {


    const inPermissions = useCallback((permissions:string | string[])=>{
        if(!roles){
            return true;
        }
        if (typeof permissions === 'string') {
            // if permissions is a string, check if role includes this permission
            return roles.includes(permissions);
        }

        if (Array.isArray(permissions)) {
            // if permissions is an array, all permissions must be included in roles
            return permissions.every(permission => roles.includes(permission));
        }
        return false;
    },[roles])

    const check:IPermissionsContextValues['check'] = useCallback((permissions = null) => {

        // console.log({roles, permissions})
        if(!roles){
            return true;
        }
        if (!permissions || roles.length == 0) return false;

        if (typeof permissions === 'string' || Array.isArray(permissions)) {
            // if permissions is a string, check if role includes this permission
            return inPermissions(permissions);
        }


        if (typeof permissions === 'object') {
            // if permissions is an object
            const { permissionsRequired, permissionsOptional } = permissions;

            if (permissionsRequired && typeof permissionsRequired === 'string' || Array.isArray(permissionsRequired)) {
                // if permissions is a string, check if role includes this permission
                return inPermissions(permissionsRequired);
            }


            if (permissionsRequired) {
                // if permissions is a string, check if role includes this permission
                return inPermissions(permissionsRequired);
            }

            if (permissionsOptional) {
                // At least one optional permission must be included in roles
                return permissionsOptional.some(permission => roles.includes(permission));
            }
        }

        return false;
    },[roles])




    return (
        <PermissionsContext.Provider value={{
            check,
        }}>
            {children}
        </PermissionsContext.Provider>
    );
};

export default PermissionsProvider;

export const usePermissions = () => useContext(PermissionsContext);
